const items = $input.all().slice(0, 10);
const out = [];

for (const item of items) {
  const f = item.json.fields || item.json;

  const company     = String(f['Company']          || '').trim();
  const contactName = String(f['Contact Name']     || '').trim();
  const title       = String(f['Title']            || '').trim();
  const linkedin    = String(f['LinkedIn URL']     || '').trim();
  const signalHook  = String(f['Signal Hook']      || '').trim();
  const notes       = String(f['Notes']            || '').trim();
  const markets     = String(f['Markets']          || '').trim();
  const isAlum      = !!(f['NexEra/Origis Alum']);

  // Only skip if we have nothing at all to work with
  if (!company && !contactName) continue;

  const needMatch    = notes.match(/NEED:\s*(.+?)(?:\n|$)/);
  const serviceMatch = notes.match(/SERVICE MATCH:\s*(.+?)(?:\n|$)/);

  out.push({
    json: {
      record_id:      item.json.id,
      contact_name:   contactName,
      title:          title,
      company:        company,
      linkedin_url:   linkedin,
      signal_hook:    signalHook,
      project_need:   needMatch    ? needMatch[1].trim()    : '',
      service_match:  serviceMatch ? serviceMatch[1].trim() : '',
      markets:        markets,
      is_alum:        isAlum,
      needs_research: !signalHook  // flag for Claude to know it needs to web search
    }
  });
}

return out;

const items = [];
const claudeItems = $input.all();
const prepItems = $('Prep Contact Data').all();

for (let i = 0; i < claudeItems.length; i++) {
  const claudeItem = claudeItems[i];
  const prepItem = prepItems[i];

  if (!prepItem) continue;

  const raw = claudeItem.json.content?.find(b => b.type === 'text')?.text
    || claudeItem.json.content?.[claudeItem.json.content.length - 1]?.text || '';

  let parsed;
  try {
    parsed = JSON.parse(raw.replace(/```json|```/g, '').trim());
  } catch(e) {
    const m = raw.match(/\{[\s\S]*\}/);
    try { parsed = m ? JSON.parse(m[0]) : null; } catch { parsed = null; }
  }

  if (!parsed || !parsed.draft_message) {
    console.log('Item ' + i + ': no draft_message found in parsed output');
    continue;
  }

  const recordId    = prepItem.json?.record_id    || '';
  const projectNeed = prepItem.json?.project_need  || '';
  const svcMatch    = prepItem.json?.service_match || '';
  const signalFound = parsed.signal_found          || '';

  if (!recordId) {
    console.log('Item ' + i + ': no record_id found');
    continue;
  }

  items.push({
    json: {
      record_id:     recordId,
      draft_message: parsed.draft_message,
      notes_update:  [
        projectNeed  ? 'NEED: '          + projectNeed  : '',
        svcMatch     ? 'SERVICE MATCH: ' + svcMatch     : '',
        parsed.dm_angle  ? 'DM ANGLE: ' + parsed.dm_angle  : '',
        signalFound  ? 'RESEARCH: '     + signalFound  : ''
      ].filter(Boolean).join('\n\n')
    }
  });
}

return items;

